# Module defining abstract base classes
# Demonstrates importing types from another module

from types_module import IMeasurable, Dimensions, Priority

@abstract
class Component(IMeasurable):
    name: str
    position: Dimensions

    def __init__(self, name: str):
        self.name = name
        self.position = Dimensions(0.0, 0.0)

    @virtual
    def get_description(self) -> str:
        return f"Component: {self.name}"

    @virtual
    def set_position(self, x: float, y: float) -> None:
        self.position = Dimensions(x, y)

    def get_area(self) -> float:
        return self.position.get_area()

@abstract
class Container(Component):
    children: list[Component]

    def __init__(self, name: str):
        super().__init__(name)
        self.children = []

    def add_child(self, child: Component) -> None:
        self.children.append(child)

    @virtual
    def get_child_count(self) -> int:
        return len(self.children)

    @abstract
    def get_priority(self) -> Priority
