# Module with concrete implementations of base classes and interfaces
# Tests cross-module inheritance and interface implementation

from types_module import IIdentifiable, Priority, Dimensions
from base_classes import Container, Component

class Button(Component, IIdentifiable):
    label: str
    id_str: str

    def __init__(self, name: str, label: str):
        super().__init__(name)
        self.label = label
        self.id_str = f"btn_{name.lower()}"

    @override
    def get_description(self) -> str:
        return f"Button '{self.label}' at ({self.position.width}, {self.position.height})"

    def get_id(self) -> str:
        return self.id_str

class Panel(Container, IIdentifiable):
    panel_id: str

    def __init__(self, name: str):
        super().__init__(name)
        self.panel_id = f"panel_{name.lower()}"

    @override
    def get_description(self) -> str:
        return f"Panel '{self.name}' with {self.get_child_count()} children"

    @override
    def get_priority(self) -> Priority:
        return Priority.HIGH

    def get_id(self) -> str:
        return self.panel_id

class TextLabel(Component):
    text: str

    def __init__(self, name: str, text: str):
        super().__init__(name)
        self.text = text

    @override
    def get_description(self) -> str:
        return f"TextLabel '{self.text}'"
